// Send
mc.thePlayer.sendQueue.addToSendQueue(new C01PacketChatMessage("gg"));
// Intercept commands
if (event.getPacket() instanceof C01PacketChatMessage) {
  C01PacketChatMessage packet = (C01PacketChatMessage) event.getPacket();
  if (packet.getMessage().startsWith(".")) { event.setCancelled(true); processCommand(packet.getMessage()); }
}
// Bypass — cancel + re-send with modification
if (event.getPacket() instanceof C01PacketChatMessage) {
  event.setCancelled(true);
  String modified = ((C01PacketChatMessage)event.getPacket()).getMessage().replace("%","");
  mc.thePlayer.sendQueue.addToSendQueue(new C01PacketChatMessage(modified));
}

